const { session, context, axios, notification, overlay } = scope;

const lon = -118.361543;
const lat = 34.088809;
const group = session.groups.find(g => g.name === 'Filming Activity');
const points = session.points[group.id].filter(p => Math.abs(p.coordinates[0] - lon) < 0.003 && Math.abs(p.coordinates[1] - lat) < 0.003);

overlay({
  message: `Found Filming Activity at N Fairfax Ave. / Romaine Str.:
	${points.map(p => p.properties[2] + ' - ' + p.properties[0]).join(', \n')}.
  `,
});
